var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"휴가 중에 이런 곳으로 불러내서 죄송해요.","JPN":"休暇中にこんなところまで呼び出してすみませんね。","ENG":"Sorry for calling you out here during your leave.","TWN":"很抱歉在休假期間把妳叫到這種地方。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자만 잡을 수 있다면, 난 아무래도 상관없어.","JPN":"犯罪者さえ捕まえられるなら、私は別に構わない。","ENG":"I don't mind as long as we can catch some criminals.","TWN":"只要能抓到罪犯，我是無所謂啦。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그래서, 무슨 일이야?","JPN":"それで、どうしたの？","ENG":"So, what is it?","TWN":"所以，發生什麼事情了？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"간략히 브리핑을 해드리자면, 용의자는 <color=#ffd34c>민병대</color>라고 불리는 무장 조직의 일원이에요.","JPN":"簡単に状況を説明すると、容疑者は<color=#ffd34c>民兵隊</color>と呼ばれる武装組織の一員です。","ENG":"To give you a quick briefing, the suspect is a member of an armed group called <color=#ffd34c>The Militia</color>.","TWN":"簡略地說明一下，嫌犯是被稱為 <color=#ffd34c>民兵</color>的武裝組織成員。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터들만을 골라서 사냥하는 사람들이죠.","JPN":"カウンターのみを狙って狩る者たちです。","ENG":"They specialize in hunting down Counters.","TWN":"是一群只狩獵制裁者的人。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......뭐? 카운터를? 어째서?","JPN":"……何？　カウンターを？　なぜ？","ENG":"What? Counters? Why?","TWN":"……什麼？狩獵制裁者？為什麼？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"민병대라는 조직은 원래 카운터 범죄의 피해자들이 결성한 조직이었거든요.","JPN":"民兵隊という組織は、元々カウンター犯罪に遭った被害者たちが結成した組織なんです。","ENG":"The Militia was initially founded by the victims of Counter crime.","TWN":"民兵這個組織，本來是由制裁者犯罪的受害者所組成的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어때요? 꽤 익숙한 사연이죠?","JPN":"どうですか？　聞いたことあるような話でしょう？","ENG":"Well? Doesn't that sound quite familiar?","TWN":"怎麼樣？很熟悉的故事吧？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥, 나랑 비교라도 할 생각이라면 틀렸어.","JPN":"ふん、私と比べるつもりなら失礼よ。","ENG":"Hmpf, don't even think about comparing them to me.","TWN":"哼，如果妳把我和那些傢伙相提並論，那妳就大錯特錯了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 녀석들은 범죄조직이고, 난 경찰이라고!","JPN":"あいつらは犯罪組織で、私は警察だから！","ENG":"They're just a crime syndicate. I'm a police officer!","TWN":"那些傢伙是犯罪集團，我是警察！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 맞아요. 민병대도 처음엔 카운터 범죄를 막기 위해 만들어진 자경조직이었지만......","JPN":"はは、そうですね。初めは民兵隊も、カウンターの犯罪を防ぐため作られた自警組織でしたが……","ENG":"Hah hah, you're right. The Militia started off as a group of vigilantes trying to stop Counter crime...","TWN":"哈哈，沒錯。民兵一開始，也是為了防止制裁者犯罪所成立的自衛組織……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"언젠가부터 행동이 과격해지더니 지금은 사적 제재를 일삼는 완전한 불법 단체가 되어 버렸어요.","JPN":"いつの間にか行動が過激になり、現在は私的制裁を加える違法団体になってしまいました。","ENG":"But they grew increasingly violent over time. Now they're a completely illegal organization that hunt Counters for revenge.","TWN":"不知道什麼時候開始，他們的行為越來越偏激，現在已經完全變成了動用私刑的非法團體。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"거기다 암암리에 민병대를 숨겨주며 협조하는 사람들도 많다 보니 꼬리를 잡기가 쉽지 않았죠.","JPN":"それに、こっそり民兵隊を匿う協力者も多いので、なかなか尻尾を掴みにくいのが現状です。","ENG":"It was tough tracking them down because they have a lot of supporters who help conceal them.","TWN":"再加上還有很多願意暗中藏匿他們，從中協助的人，所以很難抓住他們的尾巴。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하지만, 이번엔 단서를 잡았다는 거지?","JPN":"でも、今回は手がかりが見つかったのよね？","ENG":"But we found a lead this time?","TWN":"不過這次有線索了吧？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네, 이번에 민병대의 주요 멤버가 이 근처에 나타날 거라는 정보가 입수됐거든요.","JPN":"はい。民兵隊の主要メンバーが、この近くに現れるという情報を入手しました。","ENG":"Yes. I've got intel that a key member of the Militia will be appearing around here.","TWN":"是的，有情報說民兵的主要成員在這附近出沒。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"녀석들의 의도야 어찌됐건 난 상관없어.","JPN":"やつらの意図など、私には関係ない。","ENG":"I couldn't care less whether they mean well or not.","TWN":"我才不在乎犯人的動機是什麼。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자인 이상 봐주지 않을 거니까.","JPN":"犯罪者である以上、手加減はしないから。","ENG":"They're criminals in my book, and I'm not going to go easy on them.","TWN":"只要是罪犯一律逮捕。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"......조심하세요 경정님. 민병대는 카운터를 사냥하는 조직이니까요.","JPN":"……気をつけてください。民兵隊はカウンターを狩る組織ですから。","ENG":"Be careful though, Major. The Militia specializes in hunting down Counters.","TWN":"……請小心點，警正大人。畢竟民兵是專門狩獵制裁者的組織。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};